- (void)launchVappWithVappStatusCheck:(WBVAppModel *)vapp {
    oaa_ef_set(vapp.versionInfo.ef);
    NSParameterAssert(vapp.isLaunchable); // 调用前必须保证 vapp 是Launchable
    if (vapp.status == WBVappStatusResourceWaitingDownload) {
        [WBVAppResDownloadManager.sharedManager setVAppDownloadPriorityInQueue:vapp index:0];
        [self authorize:vapp successBlock:^{
            [self handleLaunchResDownloadingVApp:vapp];
        }];
    }
    else if (vapp.status & (WBVappStatusResourceDownloading | WBVappStatusResourceDownloadInterrupted)) {
        [self authorize:vapp successBlock:^{
            [self handleLaunchResDownloadingVApp:vapp];
        }];
    }
    else if (vapp.status & (WBVappStatusResourceDownloadError | WBVappStatusResourceDownloadGiveUp)) {
        [self downloadVAppRes:vapp];
        [self authorize:vapp successBlock:^{
            [self handleLaunchResDownloadingVApp:vapp];
        }];
    }
    else if (vapp.status & (WBVappStatusResourceDownloaded | WBVappStatusResourceInstalling)) {
        [self authorize:vapp successBlock:^{
            [self handleLaunchResInstallingVApp:vapp];
        }];
    }
    else if (vapp.status == WBVappStatusResourceInstalled) {
        [self authorize:vapp successBlock:^{
            [self handleLaunchResInstalledVApp:vapp];
        }];
    }
    else if (vapp.status == WBVappStatusResourceInstallError) {
        [self authorize:vapp successBlock:^{
            [self handleLaunchResInstallingVApp:vapp];
        }];
    }
    else if (vapp.status == WBVappStatusInited) {
        WBQuery *query = [WBQuery query];
        if ([vapp.launchInfo.osVersion isEqualToString:query.osVersion] && [vapp.launchInfo.engineVersion isEqualToString:query.engineVersion]) {
            [self authorize:vapp successBlock:^{
                [self launchVApp:vapp];
            }];
        } else {
            NSString *oaaVersion = [[NSString alloc] initWithFormat:@"%s", oaa_version()];
            [[WBNetworkManager defaultManager] getLatestVappInfoWithVappId:vapp.vid oaaVersion:oaaVersion callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
                if (error) {
                    [SVProgressHUD showErrorWithStatus:error.localizedDescription];
                    self.vappLaunching = false;
                    return;
                }
                if (![vapp.versionInfo.ipaHash isEqualToString:requestedVapp.ipa_hash]) {
                    // remove old ipa file
                    [vapp removeCacheFileOrDirIfExist:vapp.userInfo.ipaZipPath];
                    [vapp removeCacheFileOrDirIfExist:vapp.userInfo.ipaUnzipPath];
                    if (![vapp.versionInfo.resHash isEqualToString:requestedVapp.res_hash]) {
                        // remove old res file
                        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resZipPath];
                        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resUnzipPath];
                    }
                    [vapp updateWithVAppDetailModel:requestedVapp];
                    [self downloadVApp:vapp];
                    self.vappLaunching = false;
                } else if (![vapp.versionInfo.resHash isEqualToString:requestedVapp.res_hash]) {
                    // remove old res file
                    [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resZipPath];
                    [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resUnzipPath];
                    [vapp updateWithVAppDetailModel:requestedVapp];
                    [self downloadVAppRes:vapp];
                    [self authorize:vapp successBlock:^{
                        [self handleLaunchResDownloadingVApp:vapp];
                    }];
                } else {
                    [self authorize:vapp successBlock:^{
                        [self launchVApp:vapp];
                    }];
                }
            }];
        }
    }
    else if (vapp.status == WBVappStatusInitError) {
        [self wb_showAlertWithTitle:@"初始化失败" message:@"有可能是您的手机存储空间不足，如果持续碰到这个问题，您可以通过'客服反馈'系统寻求解决方案"];
        self.vappLaunching = false;
    }
    else {
        NSAssert(false, @"unexpected vapp check launch status");
        self.vappLaunching = false;
    }
}

- (void)presentNotLaunchableUIWithVapp:(WBVAppModel *)vapp {
    NSParameterAssert(!vapp.isLaunchable);
    switch (vapp.status) {
        case WBVappStatusWaitingDownload:
        case WBVappStatusDownloading:
        case WBVappStatusDownloadInterrupted:
            [SVProgressHUD showInfoWithStatus:@"下载中，请耐心等待一下"];
            break;
        case WBVappStatusDownloadError:
            [self handleVAppDownloadErrorWithVApp:vapp];
            break;
        case WBVappStatusDownloaded:
        case WBVappStatusWaitingInstall:
        case WBVappStatusInstalling:
            [SVProgressHUD showInfoWithStatus:@"安装中，马上就好"];
            break;
        case WBVappStatusInstallError:
            [SVProgressHUD showInfoWithStatus:@"安装失败，请重试"];
            break;
        case WBVappStatusResourceDownloadError:
        case WBVappStatusResourceDownloadGiveUp:
            [self showResourceDownloadErrorAlertForVApp:vapp];
            break;
        case WBVappStatusResourceInstallError:
            [self showResourceInstallErrorAlertForVApp:vapp];
            break;
        case WBVappStatusInitError:
            [self showInitErrorAlertForVApp:vapp];
            break;
        default:
            break;
    }
}

- (void)handleLaunchResDownloadingVApp:(WBVAppModel *)vapp {
    [self waitVAppResourceDownload:vapp completion:^(BOOL success) {
        if (!success) {
            WBCommonProgressView *progressView = (WBCommonProgressView *)self.launchVC.view.subviews[0];
            [progressView.retryButton setBlockForControlEvents:UIControlEventTouchUpInside block:^(id  _Nonnull sender) {
                NSString *oaaVersion = [[NSString alloc] initWithFormat:@"%s", oaa_version()];
                [[WBNetworkManager defaultManager] getLatestVappInfoWithVappId:vapp.vid oaaVersion:oaaVersion callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
                    if (!error) {
                        WBVAppModel *dualApp = [[WBVAppManager sharedManager] dualAppForVAppId:vapp.vid];
                        [[WBVAppManager sharedManager] fillMissingBaseFieldsForDetailModel:requestedVapp fromDualApp:dualApp];
                        WBVAppModel *vapp = [[WBVAppManager sharedManager] parseVAppHttpModel:requestedVapp];
                        [vapp updateWithVAppDetailModel:requestedVapp];
                    }
                    [self downloadVAppRes:vapp];
                    [self handleLaunchResDownloadingVApp:vapp];
                }];
            }];
            [progressView.dismissButton setBlockForControlEvents:UIControlEventTouchUpInside block:^(id  _Nonnull sender) {
                [self.launchVC dismissViewControllerAnimated:NO completion:nil];
            }];
            progressView.titleLabel.text = @"下载遇到问题，请检查网络或存储状态";
            progressView.subTitleLabel.text = @"建议保持网络畅通或清理空间后再次尝试";
            self.vappLaunching = false;
            return;
        }
        [self handleLaunchResInstallingVApp:vapp];
    }];
}

- (void)handleLaunchResInstallingVApp:(WBVAppModel *)vapp {
    [self waitVAppResourceInstall:vapp completion:^(BOOL success) {
        if (!success) {
            self.vappLaunching = false;
            [self.launchVC dismissViewControllerAnimated:NO completion:^{
                [self showResourceInstallErrorAlertForVApp:vapp];
            }];
        } else {
            [self handleLaunchResInstalledVApp:vapp];
        }
    }];
}

- (void)handleLaunchResInstalledVApp:(WBVAppModel *)vapp {
    [self initVApp:vapp completion:^(BOOL success) {
        if (!success) {
            self.vappLaunching = false;
            [self.launchVC dismissViewControllerAnimated:NO completion:^{
                if (vapp.status == WBVappStatusInitError) {
                    [self showInitErrorAlertForVApp:vapp];
                } else {
                    [self wb_showAlertWithTitle:@"启动失败" message:@"请尝试重新启动或长按图标选择“重新下载”"];
                }
            }];
        } else {
            [self launchVApp:vapp];
        }
    }];
}


