void PostNotificationOnMainThread(NSNotificationName notificationName, _Nullable id object) {
    void (^block)(void) = ^ {
        [NSNotificationCenter.defaultCenter postNotificationName:notificationName object:object];
    };
    if (pthread_main_np()) {
        block();
    } else {
        dispatch_async(dispatch_get_main_queue(), block);
    }
