- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    [route name:@"vip" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *triggerId = (id)userInfo[@"triggerId"] == [NSNull null] ? nil : userInfo[@"triggerId"];
        NSString *source = (id)userInfo[@"source"] == [NSNull null] ? nil : userInfo[@"source"];
        if (source) {
            [self presentVipPagePrivateFromPageSource:source triggerId:triggerId];
        } else {
            [self presentVipPagePrivateFromPageSource:@"link" triggerId:triggerId];
        }
    }];

    [route name:@"login" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *method = userInfo[@"method"];
        WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
        if (method.length == 0 || [method isEqualToString:@"phonenum"]) {
            loginVC.loginMethod = WBLoginMethodPhoneNumber;
        } else if ([method isEqualToString:@"password"]) {
            loginVC.loginMethod = WBLoginMethodPassword;
        } else {
            NSAssert(false, @"method invalid");
        }
        UINavigationController *loginNav = [[UINavigationController alloc] initWithRootViewController:loginVC];
        loginNav.modalPresentationStyle = UIModalPresentationFullScreen;
        [(self.presentedViewController ?: self) presentViewController:loginNav animated:YES completion:^{
            next(loginVC);
        }];
    }];
}

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setUpAppearence];
    [self addChildViewControllers];
    self.delegate = self;
    [[WBNetworkManager defaultManager] requestAllMyPromoCodeWithCallback:^(NSArray<WBPromoModel *> * _Nullable promoModels, NSError * _Nullable error) {
        NSInteger currentCount = promoModels.count;
        NSInteger lastSeenCount = WBSettingManager.sharedManager.PromoCount;
        if (currentCount < lastSeenCount) {
            WBSettingManager.sharedManager.PromoCount = currentCount;
            lastSeenCount = currentCount;
        }
        WBSettingManager.sharedManager.HasNewPromo = (currentCount > lastSeenCount);
        PostNotificationOnMainThread(WBUserMsgStatusUpdateNotification, nil);
    }];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(enterSupportPage) name:WBEnterSupportPageNotification object:nil];
}

- (void)dealloc {
    [NSNotificationCenter.defaultCenter removeObserver:self];
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self updateTabbarBadge];
//    NSMutableArray<WBVAppModel *> *apps = WBVAppManager.sharedManager.myApps;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        // 获取 SceneDelegate
        UIWindowScene *windowScene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.anyObject;
        demoSceneDelegate *sceneDelegate = (demoSceneDelegate *)windowScene.delegate;
        WBVAppModel *foundApp = [WBVAppManager.sharedManager.myApps filteredArrayUsingPredicate:
                                     [NSPredicate predicateWithFormat:@"featureStatusInfo.isOneClickSwitchOn == YES"]
        ].firstObject;
        if (!WBSettingManager.sharedManager.oneClickStart && !foundApp.featureStatusInfo.isOneClickSwitchOn) {
            [WBNetworkManager.defaultManager connectOneClickisOn:YES callback:^(id _Nullable json, NSError *_Nullable error) {}];
        }
        if (sceneDelegate.stashedShortcutItem) {
            [self handleShortcutItem:sceneDelegate.stashedShortcutItem];
            sceneDelegate.stashedShortcutItem = nil;
        } else {
            BOOL isServerOneClickSupported = (WBSettingManager.sharedManager.Benefit & WBUserBenefitOneClick) != 0;
            if (WBSettingManager.sharedManager.oneClickStart && isServerOneClickSupported) {
                if (foundApp && WBSettingManager.sharedManager.oneClickStart) {
                    [WBHomeViewController msgTappedCheckAndLaunchVApp:foundApp.bundleId];
                }
            }
        }
    });

#ifdef DEBUG
    [self authorizePushNotificationService]; // 向用户发起“同意通知的请求，如果同意，我们会将 DeviceToken 发给客户端”
#endif
}

