    NSString *title = @"资源下载失败";
    NSString *message = @"";
    NSString *errorDomain = vapp.errorInfo.errorDomain;
    NSInteger errorCode = vapp.errorInfo.errorCode;

    if ([errorDomain isEqualToString:NSURLErrorDomain]) {
        switch (errorCode) {
            case NSURLErrorNotConnectedToInternet:
            case NSURLErrorTimedOut:
                message = @"网络连接异常，请检查Wi-Fi或蜂窝数据后长按图标点击“重新下载”";
                break;
            case NSURLErrorCannotWriteToFile:
                message = @"存储空间不足，请清理设备存储后长按图标点击“重新下载”";
                break;
            default:
                message = @"网络请求失败，请尝试重新下载";
        }
    } else if ([errorDomain isEqualToString:WBErrorDomainSecurity]) {
        switch (errorCode) {
            case 10002: // SHA1不匹配
                message = @"资源校验失败，可能是下载不完整，长按图标点击“重新下载”";
                break;
            default:
                message = @"安全校验未通过，请尝试重新下载";
        }
    } else if ([errorDomain isEqualToString:WBErrorDomainHTTP]) {
        message = [NSString stringWithFormat:@"服务器错误（HTTP %ld）", (long)errorCode];
    } else if ([errorDomain isEqualToString:WBErrorDomainResDownload]) {
        switch (errorCode) {
            case 10001: // 断点续传数据丢失
                message = @"资源下载过程中断且无法恢复，请检查网络后长按图标点击“重新下载”";
                break;
        }
    } else {
        message = @"下载失败，请尝试重新下载";
    }

    [self wb_showAlertWithTitle:title message:message];
}

- (void)showResourceInstallErrorAlertForVApp:(WBVAppModel *)vapp {
    NSString *title = @"资源安装失败";
    NSString *message = @"";
    NSInteger errorCode = vapp.errorInfo.errorCode;
    NSString *errorDomain = vapp.errorInfo.errorDomain;

    if ([errorDomain isEqualToString:NSCocoaErrorDomain] || [errorDomain isEqualToString:NSPOSIXErrorDomain]) {
        switch (errorCode) {
            case 640:
            case 28:
                message = @"请确保手机储存空间充足后，长按图标选择“重新下载”";
                break;
            default:
                message = @"安装过程中发生意外错误，请长按图标选择“重新下载”";
                break;
        }
    } else {
        message = @"安装过程中发生意外错误，请长按图标选择“重新下载”";
    }

    [self wb_showAlertWithTitle:title message:message];
}

- (void)showInitErrorAlertForVApp:(WBVAppModel *)vapp {
    NSString *title = @"初始化失败";
    NSString *message = @"";
    NSInteger errorCode = vapp.errorInfo.errorCode;
    NSString *errorDomain = vapp.errorInfo.errorDomain;

    if ([errorDomain isEqualToString:WBErrorDomainVAppOAA]) {
        switch (errorCode) {
            case oaaErrFileSystemErr: // 文件系统错误
                message = @"存储空间不足或文件权限错误，请清理设备存储后长按图标点击“重新下载”";
                break;
            case oaaErrMalformedResources: // 资源文件损坏
                message = @"资源文件损坏，请长按图标点击“重新下载”";
                break;
            case oaaErrNotInited:
            case oaaErrNoSuchUser:
            case oaaErrCannotAddUser:
            case oaaErrNoSuchApp:
            case oaaErrMalformedBundle:
            case oaaErrUnknown:
            default:
                message = @"资源验证不完整，请长按图标选择“重新下载”";
                break;
        }
    } else {
        message = @"资源验证不完整，请长按图标选择“重新下载”";
    }

    [self wb_showAlertWithTitle:title message:message];
}

